class SessionManager {

    public AuthenticatedSession createSession(SamlResponse samlResponse) {
        if (samlResponse == null || samlResponse.getAssertions().isEmpty()) {
            throw new SamlProcessingException("Cannot create session from empty SAML response");
        }

        SamlAssertion assertion = samlResponse.getAssertions().get(0);
        String principal = assertion.getSubject();
        if (principal == null || principal.trim().isEmpty()) {
            throw new SamlProcessingException("Cannot create session without principal");
        }

        Instant createdAt = Instant.now();
        Instant expiresAt = assertion.getConditionsWindow().getNotOnOrAfter() != null
                ? assertion.getConditionsWindow().getNotOnOrAfter()
                : createdAt.plusSeconds(3600);

        return new AuthenticatedSession(
                UUID.randomUUID().toString(),
                principal,
                flattenAttributes(assertion.getAttributes()),
                createdAt,
                expiresAt
        );
    }

    private Map<String, String> flattenAttributes(Map<String, List<String>> attributes) {
        Map<String, String> flattened = new HashMap<>();
        for (Map.Entry<String, List<String>> entry : attributes.entrySet()) {
            List<String> values = entry.getValue();
            flattened.put(entry.getKey(), values == null || values.isEmpty() ? "" : String.join(",", values));
        }
        return flattened;
    }
}

